-- Atualizar o enum de role para os valores corretos do CRM
ALTER TABLE users MODIFY COLUMN role ENUM('admin', 'gerente', 'analista', 'assistente') NOT NULL DEFAULT 'assistente';

-- Qualquer usuário com role 'user' vira 'assistente'
UPDATE users SET role = 'assistente' WHERE role NOT IN ('admin', 'gerente', 'analista', 'assistente');

-- Owner vira admin+active+whatsappAccess
UPDATE users SET role = 'admin', status = 'active', whatsappAccess = true 
WHERE openId = (SELECT ownerOpenId FROM (SELECT openId AS ownerOpenId FROM users ORDER BY createdAt ASC LIMIT 1) AS t);

